def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity <= 0:
            priorities[i] = -np.inf
            continue
        utilization = item / bin_capacity
        if utilization > 1:
            priorities[i] = -np.inf
        else:
            score = 0
            if utilization < 0.25:
                score += 5 * (0.25 - utilization)
            elif utilization < 0.5:
                score += 3 * (0.5 - utilization)
            else:
                score += 1
            for j in range(i):
                diff = abs(bins[j] - bin_capacity)
                if diff < item:
                    score += 0.5
                else:
                    score -= 0.2
            if bin_capacity % 2 == 0:
                score *= 1.1
            else:
                score *= 0.9
            priorities[i] = score
    return priorities
